  /* Common initialization of the CPU registers */
  /* DDRS: DDRS6=1,DDRS5=1,DDRS4=0 */
  clrSetReg8Bits(DDRS, 0x10U, 0x60U);   
  /* PTS: PTS6=0 */
  clrReg8Bits(PTS, 0x40U);              
  /* PIEP: PIEP1=0 */
  clrReg8Bits(PIEP, 0x02U);             
  /* PTP: PTP1=1 */
  clrReg8Bits(PTP, 0x02U);//setReg8Bits(PTP, 0x02U);              
  /* PERP: PERP1=1 -> Pull enabled */
  setReg8Bits(PERP, 0x02U);//clrReg8Bits(PERP, 0x02U); 
  /* PPSP: PPSP1=1 -> PullDOWN */
  setReg8Bits(PPSP, 0x02U);            
  /* DDRP: DDRP1=1 */
  setReg8Bits(DDRP, 0x02U);             
  /* PER1AD: PER1AD6=0 */
  setReg8Bits(PER1AD, 0x40U);//PEx: clrReg8Bits(PER1AD, 0x40U);           
  /* DDR1AD: DDR1AD6=0 */
  clrReg8Bits(DDR1AD, 0x40U); /*1:Output -- 0:Input*/           
  /* ACMPC: ACDIEN=1 */
  setReg8Bits(ACMPC, 0x10U); 
    /* TSCR1: TEN=0,TSWAI=0,TSFRZ=0,TFFCA=0,PRNT=1,??=0,??=0,??=0 */
  setReg8(TSCR1, 0x08U);                
  /* OCPD: OCPD0=1 */
  setReg8Bits(OCPD, 0x01U);             
  /* TIOS: IOS0=1 */
  setReg8Bits(TIOS, 0x01U);             
  /* TCTL2: OM0=0,OL0=0 */
  clrReg8Bits(TCTL2, 0x03U);            
  /* TTOV: TOV0=0 */
  clrReg8Bits(TTOV, 0x01U);             
  /* TSCR2: TOI=0 */
  clrReg8Bits(TSCR2, 0x80U);            
  /* TFLG1: ??=1,??=1,C5F=1,C4F=1,C3F=1,C2F=1,C1F=1,C0F=1 */
  setReg8(TFLG1, 0xFFU);                
  /* TIE: C0I=1 */
  setReg8Bits(TIE, 0x01U);              
  /* PTPSR: PTPS7=0,PTPS6=0,PTPS5=0,PTPS4=0,PTPS3=0,PTPS2=0,PTPS1=0,PTPS0=0 */
  setReg8(PTPSR, 0x00U);            
  /* CPMUINT: LOCKIE=0,OSCIE=0 */
  clrReg8Bits(CPMUINT, 0x92U);    //0x12      
  /* CPMULVCTL: LVIE=0 */
  clrReg8Bits(CPMULVCTL, 0x02U);        
  /* IRQCR: IRQEN=0 */
  clrReg8Bits(IRQCR, 0x40U);            
  /* ATDDIEN: IEN6=1,IEN0=0 */
  clrSetReg16Bits(ATDDIEN, 0x01U, 0x40U); 
  /* PPS01AD: PPS1AD6=1 */
