  /*Enable Debug Pins*/
  setReg8Bits(DDR1AD, 0x06U); /*1:Output -- 0:Input*/ 
  setReg8Bits(PPS1AD, 0x06U);
  setReg8Bits(PER1AD, 0x06U);
  
  __EI();                              /* Enable interrupts */
